"use strict";(globalThis.webpackChunkdoqumentation=globalThis.webpackChunkdoqumentation||[]).push([[7306],{27654(i,e,a){a.r(e),a.d(e,{assets:()=>l,contentTitle:()=>s,default:()=>d,frontMatter:()=>r,metadata:()=>o,toc:()=>c});const o=JSON.parse('{"id":"learning/courses/quantum-computing-in-practice/applications-of-qc","title":"Per quali problemi i computer quantistici sono adatti?","description":"Scopri come decidiamo quali tipi di problemi potrebbero trarre vantaggio da una soluzione quantistica, e dai un\'occhiata ad alcuni esempi recenti di lavori della community.","source":"@site/i18n/it/docusaurus-plugin-content-docs/current/learning/courses/quantum-computing-in-practice/applications-of-qc.mdx","sourceDirName":"learning/courses/quantum-computing-in-practice","slug":"/learning/courses/quantum-computing-in-practice/applications-of-qc","permalink":"/learning/courses/quantum-computing-in-practice/applications-of-qc","draft":false,"unlisted":false,"editUrl":"https://github.com/JanLahmann/doQumentation/tree/main/docs/learning/courses/quantum-computing-in-practice/applications-of-qc.mdx","tags":[],"version":"current","frontMatter":{"title":"Per quali problemi i computer quantistici sono adatti?","sidebar_label":"Per quali problemi i computer quantistici sono adatti?","description":"Scopri come decidiamo quali tipi di problemi potrebbero trarre vantaggio da una soluzione quantistica, e dai un\'occhiata ad alcuni esempi recenti di lavori della community.","notebook_path":"learning/courses/quantum-computing-in-practice/applications-of-qc.ipynb"},"sidebar":"tutorialsSidebar","previous":{"title":"QAOA su scala utility","permalink":"/learning/courses/quantum-computing-in-practice/utility-scale-qaoa"},"next":{"title":"Mappatura","permalink":"/learning/courses/quantum-computing-in-practice/mapping"}}');var n=a(74848),t=a(28453);const r={title:"Per quali problemi i computer quantistici sono adatti?",sidebar_label:"Per quali problemi i computer quantistici sono adatti?",description:"Scopri come decidiamo quali tipi di problemi potrebbero trarre vantaggio da una soluzione quantistica, e dai un'occhiata ad alcuni esempi recenti di lavori della community.",notebook_path:"learning/courses/quantum-computing-in-practice/applications-of-qc.ipynb"},s=void 0,l={},c=[{value:"Introduzione",id:"introduction",level:2},{value:"Difficolt\xe0 classica vs. quantistica",id:"classical-vs-quantum-difficulty",level:2},{value:"Classi di complessit\xe0",id:"complexity-classes",level:3},{value:"I computer quantistici di oggi e i loro limiti",id:"todays-quantum-computers-and-their-limits",level:3},{value:"Aree di applicazione e casi d&#39;uso",id:"application-areas-and-use-cases",level:2},{value:"Caso d&#39;uso 1: Simulazione della dinamica degli adroni",id:"use-case-1-simulating-hadron-dynamics",level:3},{value:"Caso d&#39;uso 2: Ottimizzazione di un vetro di spin di Ising",id:"use-case-2-optimization-of-an-ising-spin-glass",level:3},{value:"Caso d&#39;uso 3: Previsione della struttura secondaria dell&#39;mRNA",id:"use-case-3-mrna-secondary-structure-prediction",level:3},{value:"Conclusione",id:"conclusion",level:2}];function u(i){const e={a:"a",annotation:"annotation",h2:"h2",h3:"h3",img:"img",li:"li",math:"math",mi:"mi",mn:"mn",mo:"mo",mrow:"mrow",ol:"ol",p:"p",semantics:"semantics",span:"span",ul:"ul",...(0,t.R)(),...i.components},{IBMVideo:o}=e;return o||function(i,e){throw new Error("Expected "+(e?"component":"object")+" `"+i+"` to be defined: you likely forgot to import, pass, or provide it.")}("IBMVideo",!0),(0,n.jsxs)(n.Fragment,{children:["\n","\n",(0,n.jsxs)(e.p,{children:["Guarda il video sulle applicazioni del calcolo quantistico di Olivia Lanes, oppure apri il video in una finestra separata su ",(0,n.jsx)(e.a,{href:"https://youtu.be/33QmsXhIlpU",children:"YouTube."})]}),"\n",(0,n.jsx)(o,{id:"134063426",title:"In this video, Olivia Lanes describes several possible applications of quantum computing at the utility scale. These include simulating hadrons and spin glasses, as well as modeling protein structure."}),"\n",(0,n.jsx)(e.h2,{id:"introduction",children:"Introduzione"}),"\n",(0,n.jsx)(e.p,{children:"Nella lezione precedente abbiamo affrontato in profondit\xe0 un singolo problema: la risoluzione del problema di ottimizzazione Max-Cut mediante la formulazione QUBO. Oggi adotteremo un approccio diverso e discuteremo le applicazioni a breve termine in modo pi\xf9 ampio. Inizieremo dandoti un'idea di come decidiamo quali tipi di problemi potrebbero trarre vantaggio da una soluzione quantistica. Poi esamineremo alcuni esempi recenti di lavori svolti nella nostra community. Questo ti aiuter\xe0 a sviluppare un'intuizione per i diversi tipi di problemi del calcolo quantistico e per come li affrontiamo."}),"\n",(0,n.jsx)(e.h2,{id:"classical-vs-quantum-difficulty",children:"Difficolt\xe0 classica vs. quantistica"}),"\n",(0,n.jsx)(e.p,{children:"Prima di entrare negli esempi, discutiamo come studiamo e categorizziamo la difficolt\xe0 dei vari problemi. Alcuni problemi possono essere risolti facilmente su un computer classico, e non abbiamo bisogno di un computer quantistico per risolverli. D'altro canto, esistono problemi molto difficili per i quali i computer quantistici sono necessari. Un famoso esempio \xe8 trovare i fattori primi di numeri interi enormi. La crittografia RSA si basa sulla difficolt\xe0 di questo problema, e l'algoritmo di Shor \xe8 stato progettato per risolverlo su un computer quantistico. Un altro esempio \xe8 trovare una soluzione in un insieme di dati non ordinato \u2014 questo pu\xf2 essere teoricamente risolto dall'algoritmo quantistico noto come algoritmo di Grover. Tuttavia, la maggior parte degli esperti concorda sul fatto che questi tipi di algoritmi richiederanno l'implementazione della correzione degli errori, e la tecnologia non \xe8 ancora pronta."}),"\n",(0,n.jsx)(e.p,{children:"Quindi, stiamo cercando problemi che possiamo affrontare in una zona di equilibrio tra il molto facile e il molto difficile \u2014 problemi che i computer quantistici di oggi possono affrontare, ma con cui i computer classici fanno fatica."}),"\n",(0,n.jsx)(e.h3,{id:"complexity-classes",children:"Classi di complessit\xe0"}),"\n",(0,n.jsx)(e.p,{children:"La difficolt\xe0 di questi problemi \xe8 categorizzata e analizzata in una branca dell'informatica chiamata teoria della complessit\xe0 computazionale. Esistono moltissime classi di complessit\xe0 diversi nell'informatica classica, ma alcune delle pi\xf9 fondamentali sono:"}),"\n",(0,n.jsxs)(e.ul,{children:["\n",(0,n.jsx)(e.li,{children:"P: Problemi che possono essere risolti in tempo polinomiale all'aumentare della scala del problema. Sono facili da risolvere."}),"\n",(0,n.jsx)(e.li,{children:"NP: Sta per nondeterministic polynomial (polinomiale non deterministico). Questi problemi non possono necessariamente essere risolti in tempo polinomiale, ma le loro soluzioni possono essere verificate in tempo polinomiale."}),"\n",(0,n.jsx)(e.li,{children:"NP-completo comprende i problemi pi\xf9 difficili in NP e non ha soluzioni polinomiali note. \xc8 qui che vivono problemi famosi come il commesso viaggiatore e il gioco del Sudoku."}),"\n",(0,n.jsx)(e.li,{children:"BPP, o bounded-error polynomial problems (problemi polinomiali con errore limitato), che possono essere risolti entro una certa soglia di errore da un computer classico probabilistico in tempo polinomiale."}),"\n"]}),"\n",(0,n.jsx)(e.p,{children:"Quando fu inventato il concetto di calcolo quantistico, le persone dedicarono considerevoli sforzi per capire quale classe di problemi questi nuovi tipi di computer sarebbero stati in grado di risolvere in modo efficiente. Fu inventata una nuova classe di problemi:"}),"\n",(0,n.jsxs)(e.ul,{children:["\n",(0,n.jsx)(e.li,{children:"BQP, o bounded-error quantum polynomial problems (problemi quantistici polinomiali con errore limitato). Questo \xe8 l'equivalente quantistico del BPP: \xe8 la classe di problemi decisionali risolvibili da un computer quantistico in tempo polinomiale con una piccola probabilit\xe0 di errore."}),"\n"]}),"\n",(0,n.jsx)(e.p,{children:(0,n.jsx)(e.img,{alt:"Relazioni supposte tra le classi di complessit\xe0",src:a(52600).A+"",width:"976",height:"682"})}),"\n",(0,n.jsx)(e.p,{children:"Tutte queste classi vivono in una classe pi\xf9 grande che chiamiamo PSPACE. Sopra \xe8 mostrato un diagramma delle relazioni supposte tra alcune delle classi di complessit\xe0, ma \xe8 molto difficile dimostrarlo definitivamente in modo matematico. Noterai che BQP non si sovrappone necessariamente a NP-completo. Ma potresti aver comunque visto alcuni approcci di calcolo quantistico che cercano di risolvere problemi in NP-completo."}),"\n",(0,n.jsx)(e.p,{children:"Un malinteso comune \xe8 che non abbia senso esplorare soluzioni quantistiche per problemi in cui non \xe8 stata trovata una prova matematica di un'accelerazione quantistica. Ma trovare una prova matematica che un algoritmo quantistico sia pi\xf9 veloce della sua controparte classica \xe8 difficile. Quelli di Shor e di Grover sono due dei pochi esempi in cui ci\xf2 \xe8 stato fatto finora. In realt\xe0, dimostrare rigorosamente che P e NP sono diversi \xe8 una delle questioni aperte pi\xf9 famose di tutta la matematica, anche se l'intuizione ci dice che devono esserlo."}),"\n",(0,n.jsx)(e.p,{children:"Ma il modo in cui un algoritmo scala con l'aumentare della dimensione del problema \u2014 che \xe8 ci\xf2 che si riflette nella classe di complessit\xe0 \u2014 non \xe8 sempre la caratteristica pi\xf9 rilevante di un algoritmo. Questa scalabilit\xe0 \xe8 spesso lo scenario peggiore. \xc8 del tutto possibile che, in pratica, lo scenario peggiore non sia quello che incontriamo pi\xf9 frequentemente."}),"\n",(0,n.jsx)(e.p,{children:"Il fatto che le prove di difficolt\xe0 siano insidiose non significa che non possiamo fare progressi. Introduciamo l'idea di soluzioni euristiche. Se sei un sperimentatore probabilmente conosci e ami questi tipi di soluzioni. Un'euristica \xe8 qualsiasi approccio alla soluzione di un problema che sia pragmatico, ma non necessariamente ottimale, poich\xe9 le soluzioni non devono essere ottimali per essere utili. Pensa per esempio alle applicazioni finanziarie. Non abbiamo ancora trovato un'accelerazione esponenziale per la maggior parte degli algoritmi finanziari per cui il calcolo quantistico potrebbe essere usato, ma non abbiamo bisogno di una soluzione ottimale. In finanza, anche una soluzione che sia solo lo 0,1% pi\xf9 efficiente potrebbe equivalere a miliardi di dollari di profitto."}),"\n",(0,n.jsx)(e.h3,{id:"todays-quantum-computers-and-their-limits",children:"I computer quantistici di oggi e i loro limiti"}),"\n",(0,n.jsx)(e.p,{children:"Quindi, come facciamo a sapere quali casi d'uso e problemi potrebbero essere adatti al calcolo quantistico in questo momento? C'\xe8 una buona ragione per credere che l'utilit\xe0 quantistica, o anche il vantaggio quantistico, possa essere trovata ora o nel prossimo futuro?"}),"\n",(0,n.jsx)(e.p,{children:"Forse \xe8 pi\xf9 facile nominare prima le cose che il problema certamente non dovrebbe avere. Non pu\xf2 richiedere un numero enorme di qubit. Non abbiamo ancora processori con migliaia o milioni di qubit disponibili. Questa \xe8 una delle principali ragioni per cui l'algoritmo di Shor e simili sono ancora cos\xec lontani dall'essere realizzati. I circuiti non possono nemmeno essere troppo profondi. Il limite alla profondit\xe0 del circuito dipende da molti fattori, ma in generale, se il tuo esperimento richiede una profondit\xe0 che non hai ancora visto raggiunta in letteratura, probabilmente non funzioner\xe0. E infine, qualsiasi tipo di algoritmo che sappiamo richiedere la correzione degli errori non pu\xf2 ancora essere eseguito."}),"\n",(0,n.jsxs)(e.p,{children:["Tutte queste limitazioni sono affrontate nella ",(0,n.jsx)(e.a,{href:"https://www.ibm.com/quantum/technology#roadmap",children:"roadmap di IBM Quantum\xae"})," e prevediamo di raggiungere la correzione degli errori all'inizio degli anni 2030, ma per ora dobbiamo cercare esperimenti che sfruttino la maggior parte dei qubit attualmente disponibili su un dato QPU. Sottolineiamo anche l'importanza della mitigazione e della soppressione degli errori. E infine, dovrebbe esserci un'evidente estensione verso future applicazioni che sarebbero importanti per la societ\xe0 e che potremmo vedere portare eventualmente a un vantaggio quantistico."]}),"\n",(0,n.jsx)(e.h2,{id:"application-areas-and-use-cases",children:"Aree di applicazione e casi d'uso"}),"\n",(0,n.jsx)(e.p,{children:"Parliamo ora di alcuni esempi di casi d'uso, che rientrano in tre categorie principali che abbiamo identificato come pi\xf9 probabili a vedere risultati favorevoli nel breve e medio termine:"}),"\n",(0,n.jsxs)(e.ol,{children:["\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsxs)(e.p,{children:["Simulazioni della natura. I metodi classici attuali per le simulazioni atomiche e molecolari sono limitati da descrizioni matematiche inefficienti della struttura atomica. Memorizzare e manipolare uno stato quantistico richiede risorse esponenzialmente maggiori su un computer classico, ma pu\xf2 essere fatto in modo efficiente su un computer quantistico. Questo potrebbe portare a sviluppi nel sequestro dell'anidride carbonica, batterie alternative, o all'invenzione di nuovi farmaci. Alcuni algoritmi particolarmente rilevanti in quest'area sono: il Variational Quantum Eigensolver (VQE), usato per stimare certe propriet\xe0 di un materiale, come gli stati di equilibrio o di energia minima; l'algoritmo Time Dynamics Simulation (TDS), usato per stimare funzioni di risposta o propriet\xe0 spettrali dei materiali; e un nuovo arrivato, ",(0,n.jsx)(e.a,{href:"/learning/courses/quantum-diagonalization-algorithms/sqd-overview",children:"Sample-based Quantum Diagonalization (SQD)"}),", di cui pensiamo si sentir\xe0 parlare molto di pi\xf9 nel prossimo futuro."]}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Ottimizzazione. Quest'area \xe8 onnipresente nell'informatica, quindi i casi d'uso sono numerosi e variegati. Alcuni esempi di cui si sente parlare molto sono l'ottimizzazione del portafoglio in finanza, la progettazione industriale, e la distribuzione e la catena di approvvigionamento. L'algoritmo pi\xf9 comune che probabilmente sentirai in relazione alla finanza \xe8 quello che abbiamo gi\xe0 trattato in una certa misura: il quantum approximate optimization algorithm, o QAOA."}),"\n"]}),"\n",(0,n.jsxs)(e.li,{children:["\n",(0,n.jsx)(e.p,{children:"Quantum machine learning. Quest'area ha generato molto entusiasmo negli ultimi anni, ma \xe8 probabile che il QML non sar\xe0 utile cos\xec presto come lo sar\xe0 la simulazione. Tuttavia ci sono comunque alcuni algoritmi impressionanti su cui si sta lavorando per affrontare alcuni casi d'uso molto importanti. Alcuni di questi possibili casi d'uso sono l'elaborazione del linguaggio naturale, l'analisi del traffico di rete, e persino il rilevamento di frodi nelle transazioni finanziarie. Algoritmi rilevanti in quest'area sono la quantum support vector machine (QSVM), le quantum neural networks (QNN), e le quantum generative adversarial networks."}),"\n"]}),"\n"]}),"\n",(0,n.jsx)(e.p,{children:"All'interno di queste ampie aree applicative, la community vede il vantaggio dei gruppi che lavorano insieme focalizzati su un argomento pi\xf9 specifico. IBM\xae ha guidato un'iniziativa chiamata Working Groups per cercare di aiutare i collaboratori a incontrarsi e creare una sinergia produttiva in quattro aree specifiche: sanit\xe0 e scienze della vita, materiali e high-performance computing (HPC), fisica delle alte energie, e ottimizzazione. Di recente \xe8 stato creato anche un quinto gruppo di lavoro sulla sostenibilit\xe0."}),"\n",(0,n.jsx)(e.p,{children:"Ora andremo a esaminare da vicino alcuni problemi affrontati di recente da alcuni di questi gruppi di lavoro. L'obiettivo principale qui non \xe8 capire ogni dettaglio di un esperimento \u2014 questo pu\xf2 essere intimidatorio anche per gli esperti se l'articolo \xe8 leggermente fuori dalla loro area di competenza. L'obiettivo \xe8 semplicemente aiutare a sviluppare un'intuizione per i tipi di problemi per cui i computer quantistici sono adatti e come affrontarli. E se sei interessato, ti incoraggiamo a leggere i paper completi."}),"\n",(0,n.jsx)(e.h3,{id:"use-case-1-simulating-hadron-dynamics",children:"Caso d'uso 1: Simulazione della dinamica degli adroni"}),"\n",(0,n.jsxs)(e.p,{children:["Per prima cosa, approfondiremo un paper del gruppo di Martin Savage all'Universit\xe0 di Washington intitolato ",(0,n.jsx)(e.a,{href:"https://journals.aps.org/prd/abstract/10.1103/PhysRevD.109.114510",children:"Quantum Simulations of Hadron Dynamics in the Schwinger Model Using 112 Qubits"}),"."]}),"\n",(0,n.jsx)(e.p,{children:'Se non sei un fisico delle alte energie, potresti comunque avere familiarit\xe0 con il termine "adrone", come nel Large Hadron Collider (LHC), che \xe8 il gigantesco acceleratore di particelle, di 27 km di circonferenza, che ha reso possibile osservare finalmente il bosone di Higgs. Un adrone \xe8 una particella composta subatomica costituita da altre particelle pi\xf9 piccole chiamate quark. Alcuni esempi di adroni sono i neutroni e i protoni.'}),"\n",(0,n.jsx)(e.p,{children:"Per un po' di contesto, l'LHC \xe8 stato costruito per consentire lo studio della fisica fondamentale facendo collidere particelle ad energie elevatissime. Con l'LHC, gli scienziati sperano di saperne di pi\xf9 sull'universo primordiale e sulle leggi fondamentali della natura. In linea di principio, le interazioni di queste particelle potrebbero essere simulate dall'inizio alla fine con un computer quantistico sufficientemente potente. Non siamo ancora arrivati, ma stiamo progredendo."}),"\n",(0,n.jsx)(e.p,{children:"Il modello di Schwinger \xe8 un modello semplice e popolare usato per simulare alcune di queste dinamiche. \xc8 un modello che descrive il comportamento di elettroni e positroni che interagiscono tramite fotoni in 1+1D, ossia nel tempo e in una dimensione spaziale. Il modello ha molte somiglianze con la cromodinamica quantistica (QCD), che descrive come quark e adroni interagiscono, ma la QCD \xe8 estremamente difficile da simulare. Quindi, il modello di Schwinger viene spesso usato come modello semplificato per indagare alcuni fenomeni comuni a entrambi."}),"\n",(0,n.jsx)(e.p,{children:"Per capire perch\xe9 hanno affrontato questo problema, poniamoci una serie di domande."}),"\n",(0,n.jsx)(e.p,{children:"Prima di tutto, perch\xe9 avevano motivo di credere che simulare questo su un computer quantistico avrebbe funzionato? In questo caso, gli elettroni e i positroni nel modello di Schwinger hanno un effetto di schermatura, causando la decadenza esponenziale delle correlazioni tra fermioni distanti con la separazione. Questo significa che non ci sono tante interazioni a lungo raggio necessarie da un qubit su un lato del chip a un altro, il che sappiamo essere molto soggetto a errori. Quindi, questo \xe8 ottimo per l'hardware che abbiamo disponibile oggi."}),"\n",(0,n.jsx)(e.p,{children:"Poi, perch\xe9 questo argomento \xe8 di interesse? La fisica delle alte energie in generale \xe8 di grande interesse. Le persone erano disposte a spendere miliardi di dollari per costruire l'LHC, e molte migliaia di scienziati e tecnici in tutto il mondo hanno dedicato le loro carriere a questo campo. Sebbene il modello di Schwinger sia semplicistico e non sia progettato per coprire tre dimensioni spaziali, \xe8 comunque una semplificazione utile della teoria completa."}),"\n",(0,n.jsx)(e.p,{children:"Infine, come \xe8 stato svolto questo lavoro, o come avremmo affrontato il problema se stessimo cercando di continuare questo lavoro? Negli esperimenti di simulazione, il VQE \xe8 uno degli approcci pi\xf9 comuni, e il primo passo \xe8 quasi sempre lo stesso: preparare lo stato fondamentale. In questo caso, \xe8 uno stato di vuoto. In questo esperimento, usano una nuova versione del VQE chiamata SC-ADAPT-VQE (che sta per Scalable Circuits - Adaptive Derivative-Assembled Pseudo-Trotter ansatz-VQE) per preparare sia lo stato fondamentale che il pacchetto d'onda degli adroni su questo vuoto. Il passo successivo \xe8 lasciare che gli adroni evolvano nel tempo. Infine, si identificano gli osservabili da misurare e li si misura."}),"\n",(0,n.jsx)(e.p,{children:"Se questi passaggi suonano un po' familiari, a parte la parte del pacchetto d'onda degli adroni, \xe8 perch\xe9 sono molto simili a quanto abbiamo trattato nell'esempio QAOA nella lezione precedente. Partiamo da uno stato familiare (qui lo stato di vuoto), e poi lasciamo che evolva nel tempo con una serie di Hamiltoniane esponenziate. Molti algoritmi variazionali seguono questo approccio generale. Una grande differenza qui, per\xf2, \xe8 che creiamo il pacchetto d'onda degli adroni centrato nel nostro circuito, prima di iniziare a lasciarlo evolvere."}),"\n",(0,n.jsx)(e.p,{children:"Quindi, come creiamo il pacchetto d'onda? Sul vuoto, un adrone pu\xf2 essere eccitato creando una coppia fermione-antifermione su siti adiacenti. Preparando una sovrapposizione di tali adroni in luoghi diversi, si pu\xf2 preparare un pacchetto d'onda arbitrario. Gli autori hanno centrato il loro pacchetto d'onda nel mezzo del circuito per osservare l'evoluzione senza colpire un confine."}),"\n",(0,n.jsx)(e.p,{children:"Ma ricorda: il nome del gioco quando si lavora con QPU rumorosi \xe8 mantenere la profondit\xe0 del circuito gestibile. Per fare questo, il protocollo SC-ADAPT-VQE usa simmetrie e gerarchie nelle scale di lunghezza per determinare circuiti quantistici a bassa profondit\xe0 per la preparazione degli stati. Questo creer\xe0 un ansatz con un numero minore di parametri, e quindi, una profondit\xe0 minore."}),"\n",(0,n.jsx)(e.p,{children:"L'esperimento \xe8 stato eseguito su un dispositivo IBM Quantum Heron e ha incluso diversi tipi di mitigazione e soppressione degli errori: il decoupling dinamico, l'estrapolazione a zero rumore, il Pauli twirling, e una tecnica sviluppata di recente chiamata operator decoherence renormalization."}),"\n",(0,n.jsx)(e.p,{children:(0,n.jsx)(e.img,{alt:"Risultati delle simulazioni degli adroni",src:a(77894).A+"",width:"1158",height:"838"})}),"\n",(0,n.jsx)(e.p,{children:"Sopra \xe8 riportata una figura del paper che mostra l'osservabile di interesse, il condensato chirale, che \xe8 fondamentalmente una fase superfluida degli adroni. Possiamo vedere il pacchetto d'onda al centro dei siti designati per eseguire questo esperimento. Le linee nere sono i risultati privi di errori della simulazione classica (computazionalmente costosa), mentre i punti con barre di errore sono i risultati del computer quantistico IBM da 133 qubit, Torino."}),"\n",(0,n.jsxs)(e.p,{children:["Vediamo due diversi passi temporali nell'evoluzione del pacchetto d'onda. Al tempo ",(0,n.jsxs)(e.span,{className:"katex",children:[(0,n.jsx)(e.span,{className:"katex-mathml",children:(0,n.jsx)(e.math,{xmlns:"http://www.w3.org/1998/Math/MathML",children:(0,n.jsxs)(e.semantics,{children:[(0,n.jsxs)(e.mrow,{children:[(0,n.jsx)(e.mi,{children:"t"}),(0,n.jsx)(e.mo,{children:"="}),(0,n.jsx)(e.mn,{children:"1"})]}),(0,n.jsx)(e.annotation,{encoding:"application/x-tex",children:"t=1"})]})})}),(0,n.jsxs)(e.span,{className:"katex-html","aria-hidden":"true",children:[(0,n.jsxs)(e.span,{className:"base",children:[(0,n.jsx)(e.span,{className:"strut",style:{height:"0.6151em"}}),(0,n.jsx)(e.span,{className:"mord mathnormal",children:"t"}),(0,n.jsx)(e.span,{className:"mspace",style:{marginRight:"0.2778em"}}),(0,n.jsx)(e.span,{className:"mrel",children:"="}),(0,n.jsx)(e.span,{className:"mspace",style:{marginRight:"0.2778em"}})]}),(0,n.jsxs)(e.span,{className:"base",children:[(0,n.jsx)(e.span,{className:"strut",style:{height:"0.6444em"}}),(0,n.jsx)(e.span,{className:"mord",children:"1"})]})]})]}),", puoi vedere che il condensato chirale \xe8 stretto e localizzato, e corrisponde anche bene alla simulazione classica. A ",(0,n.jsxs)(e.span,{className:"katex",children:[(0,n.jsx)(e.span,{className:"katex-mathml",children:(0,n.jsx)(e.math,{xmlns:"http://www.w3.org/1998/Math/MathML",children:(0,n.jsxs)(e.semantics,{children:[(0,n.jsxs)(e.mrow,{children:[(0,n.jsx)(e.mi,{children:"t"}),(0,n.jsx)(e.mo,{children:"="}),(0,n.jsx)(e.mn,{children:"14"})]}),(0,n.jsx)(e.annotation,{encoding:"application/x-tex",children:"t=14"})]})})}),(0,n.jsxs)(e.span,{className:"katex-html","aria-hidden":"true",children:[(0,n.jsxs)(e.span,{className:"base",children:[(0,n.jsx)(e.span,{className:"strut",style:{height:"0.6151em"}}),(0,n.jsx)(e.span,{className:"mord mathnormal",children:"t"}),(0,n.jsx)(e.span,{className:"mspace",style:{marginRight:"0.2778em"}}),(0,n.jsx)(e.span,{className:"mrel",children:"="}),(0,n.jsx)(e.span,{className:"mspace",style:{marginRight:"0.2778em"}})]}),(0,n.jsxs)(e.span,{className:"base",children:[(0,n.jsx)(e.span,{className:"strut",style:{height:"0.6444em"}}),(0,n.jsx)(e.span,{className:"mord",children:"14"})]})]})]}),", \xe8 molto pi\xf9 diffuso. Il confronto con il simulatore non \xe8 pi\xf9 cos\xec perfetto ora, ma si vede ancora chiaramente un ottimo accordo tra teoria e dati, il che \xe8 incoraggiante."]}),"\n",(0,n.jsx)(e.p,{children:"In conclusione, questo \xe8 un esempio molto interessante del tipo di lavoro di simulazione a cui potresti non pensare inizialmente di applicare il calcolo quantistico, ma che mostra una reale promessa. Non \xe8 perfetto, ma non devi essere un esperto di fisica delle particelle per vedere che il computer quantistico prevede con precisione la propagazione verso l'esterno del pacchetto d'onda, che \xe8 esattamente quello che ci aspetteremmo di trovare. Si spera che i lavori futuri in quest'area continuino e che i fisici delle alte energie continuino a trovare modi per incorporare il calcolo quantistico nei loro flussi di lavoro. L'obiettivo \xe8 risolvere problemi teorici difficili in modo pi\xf9 preciso e usare esperimenti per accettare o rifiutare teorie nella speranza di scoprire nuova fisica, costruire rilevatori migliori, e portare a una migliore comprensione della natura al suo livello pi\xf9 fondamentale."}),"\n",(0,n.jsx)(e.h3,{id:"use-case-2-optimization-of-an-ising-spin-glass",children:"Caso d'uso 2: Ottimizzazione di un vetro di spin di Ising"}),"\n",(0,n.jsxs)(e.p,{children:["Il nostro prossimo esempio si concentra sull'ottimizzazione e sar\xe0 un'analisi approfondita di un paper intitolato ",(0,n.jsx)(e.a,{href:"https://arxiv.org/abs/2405.13898",children:"Bias-Field Digitized Counterdiabatic Quantum Optimization"}),", realizzato da membri del team di Kipu Quantum e dell'Universit\xe0 dei Paesi Baschi in Spagna."]}),"\n",(0,n.jsx)(e.p,{children:'Nel paper, gli autori hanno sviluppato un nuovo metodo di ottimizzazione e lo hanno applicato per trovare lo stato fondamentale di un vetro di spin di Ising. Come discusso in precedenza, molti problemi di ottimizzazione combinatoria possono essere riformulati come ricerca degli stati a bassa energia degli Hamiltoniani di Ising. Il modello di Ising descrive l\'interazione di un array di spin microscopici. In alcuni regimi, il modello prevede che gli spin si comportino come un vetro, in cui i momenti magnetici sono disordinati al di sopra di una cosiddetta "temperatura di congelamento."'}),"\n",(0,n.jsx)(e.p,{children:"Inizieremo come prima con una serie di definizioni. La prima \xe8 controdiabatic (controdiabiatico), un tipo di evoluzione che sopprime gli effetti non adiabatico sperimentati da un sistema, indipendentemente dalla velocit\xe0 con cui avvengono tali processi. Ricorda il teorema adiabatico dell'episodio precedente \u2014 di solito \xe8 necessario far evolvere un sistema molto lentamente se si vuole che rimanga nello stato fondamentale. Questo \xe8 un grosso problema perch\xe9 pi\xf9 lentamente dobbiamo far evolvere le cose, pi\xf9 tempo abbiamo perch\xe9 si verifichino errori. Il driving controdiabiatico (CD) mira a combattere questo aggiungendo termini che contrastino queste eccitazioni indesiderate. L'idea principale \xe8 accelerare l'intero esperimento e ridurre la profondit\xe0 del circuito quantistico sopprimendo le eccitazioni che potrebbero causare transizioni spurie."}),"\n",(0,n.jsx)(e.p,{children:"Ora per l'altro termine tecnico nel titolo: il campo di bias. Altri algoritmi iterativi, come il VQE, prendono parametri classici negli stati e usano ottimizzatori classici per cercare nello spazio dei parametri multidimensionale il set di parametri che produce un valore di aspettativa minimo per un Hamiltoniano fisso. In questo caso, invece, variano l'Hamiltoniano ogni volta, spostandosi adiabaticamente da un caso noto al caso di interesse. Per cambiare l'Hamiltoniano, applicano semplicemente direttamente il valore di aspettativa Pauli-Z da un'iterazione come campo di bias nell'Hamiltoniano per l'iterazione successiva. In questo modo, guidano le dinamiche verso la soluzione effettiva senza la necessit\xe0 di ottimizzatori classici."}),"\n",(0,n.jsx)(e.p,{children:"Quindi, perch\xe9 questo esperimento \xe8 di interesse? I vetri di spin di Ising sono di fondamentale interesse in fisica, ma questo nuovo approccio \xe8 ancora pi\xf9 generale. Potrebbe essere applicato a molti problemi di ottimizzazione, quindi il paper \xe8 di ampio interesse."}),"\n",(0,n.jsx)(e.p,{children:"E perch\xe9 pensavamo che avrebbe funzionato? L'algoritmo che propongono accelera l'evoluzione per ridurre la profondit\xe0 del circuito, sopprimendo al contempo le transizioni non adiabatiche. Inoltre, non si basa su alcuna subroutine di ottimizzazione classica, che pu\xf2 essere un problema che porta a plateau piatti (barren plateaus) e al blocco in minimi locali. Infine, gli autori si assicurano anche di allineare le interazioni nell'Hamiltoniano del problema con la connettivit\xe0 hardware nei QPU reali, il che \xe8 sempre molto importante."}),"\n",(0,n.jsx)(e.p,{children:"Quindi, come funziona questo metodo? Di nuovo, non usa alcun ottimizzatore classico, a differenza della maggior parte degli altri algoritmi quantistici iterativi. Invece, alimentando la soluzione di ogni iterazione come input per la successiva, l'algoritmo di ottimizzazione quantistica digitizzato bias-field raffina incrementalmente lo stato fondamentale, avvicinandolo sempre di pi\xf9 allo stato evoluto finale. E combinato con i protocolli controdiabatici, possiamo farlo anche con circuiti quantistici a bassa profondit\xe0 che dovrebbero funzionare senza problemi su hardware rumoroso."}),"\n",(0,n.jsx)(e.p,{children:"Quindi, quando l'esperimento \xe8 stato eseguito, gli autori hanno scelto di eseguire l'algoritmo sul computer IBM Quantum da 127 qubit Brisbane. Di seguito \xe8 riportata una figura che mostra l'8a iterazione dell'algoritmo di ottimizzazione per un'istanza di vetro di spin generata casualmente con interazioni tra vicini pi\xf9 prossimi su 100 qubit. Confrontano i risultati della simulazione classica idealizzata di DCQO e BF-DCQO, nonch\xe9 il risultato sperimentale eseguito sul computer quantistico. Mostrano anche il risultato di un risolutore classico chiamato Gurobi come riferimento. Con sole 10 iterazioni, BF-DCQO fornisce un miglioramento drastico rispetto a DCQO. Sebbene il risultato sperimentale sia un po' diverso dal risultato ideale a causa del rumore, le prestazioni sono ancora migliori del DCQO ideale. Questo dimostra che si stanno ancora facendo ottimi progressi per quanto riguarda l'ottimizzazione quantistica e buoni risultati vengono riportati su oltre 100 qubit per una delle prime volte."}),"\n",(0,n.jsx)(e.p,{children:(0,n.jsx)(e.img,{alt:"Risultati del paper sul vetro di spin di Ising",src:a(43410).A+"",width:"976",height:"682"})}),"\n",(0,n.jsx)(e.h3,{id:"use-case-3-mrna-secondary-structure-prediction",children:"Caso d'uso 3: Previsione della struttura secondaria dell'mRNA"}),"\n",(0,n.jsxs)(e.p,{children:["Infine, discuteremo un paper di Moderna Pharmaceuticals intitolato ",(0,n.jsx)(e.a,{href:"https://arxiv.org/abs/2405.20328",children:"mRNA Secondary Structure Prediction Using Utility-Scale Quantum Computers"}),"."]}),"\n",(0,n.jsx)(e.p,{children:"Prima di tutto, un breve ripasso sull'mRNA. L'RNA messaggero \xe8 un tipo di RNA coinvolto nella sintesi proteica. Sostanzialmente legge le istruzioni fornite dal DNA. La struttura secondaria dell'mRNA \xe8 il modo in cui la catena \xe8 ripiegata, come mostrato nel diagramma seguente. E il problema di previsione della struttura secondaria dell'RNA \xe8 il problema di trovare il ripiegamento pi\xf9 stabile della sequenza di basi o nucleotidi che compongono l'RNA: adenina (A), citosina (C), uracile (U) e guanina (G). L'immagine seguente mostra alcune strutture di ripiegamento comuni trovate nell'mRNA; ogni colore rappresenta un tipo diverso di struttura secondaria. Cosa renda una struttura pi\xf9 favorevole delle altre non \xe8 ben compreso; tutto ci\xf2 che possiamo fare \xe8 calcolare quale struttura produce l'energia libera pi\xf9 bassa rispetto allo stato non ripiegato. Ed \xe8 qui che entrano in gioco i computer quantistici."}),"\n",(0,n.jsx)(e.p,{children:(0,n.jsx)(e.img,{alt:"Diagramma della struttura secondaria dell&#39;mRNA",src:a(41923).A+"",width:"638",height:"842"})}),"\n",(0,n.jsx)(e.p,{children:"Quindi, perch\xe9 le strutture secondarie dell'mRNA sono importanti? La loro previsione accurata \xe8 fondamentale non solo per comprendere il DNA e i nostri geni, ma anche per progettare terapeutici basati sull'RNA, come il vaccino contro il COVID-19."}),"\n",(0,n.jsx)(e.p,{children:"Da tempo \xe8 noto che questo \xe8 un formidabile problema di ottimizzazione per i computer classici a causa del vasto numero di configurazioni possibili. Per alcune configurazioni, \xe8 noto che si tratta di un problema NP-completo. Tuttavia, su un computer quantistico, possiamo formulare la previsione della struttura secondaria come un problema di ottimizzazione binaria \u2014 qualcosa che sappiamo come gestire. Inoltre, in letteratura erano gi\xe0 presenti prove di previsioni accurate dell'RNA su dispositivi quantistici su piccola scala e simulatori quantistici. Ma avrebbe funzionato su hardware pi\xf9 grande?"}),"\n",(0,n.jsx)(e.p,{children:"Questo esperimento \xe8 stato eseguito usando qualcosa chiamato conditional value at risk variational quantum eigensolver, che \xe8 una modifica di un algoritmo VQE tradizionale e ci si aspetta che raggiunga una convergenza migliore."}),"\n",(0,n.jsx)(e.p,{children:(0,n.jsx)(e.img,{alt:"Risultati del paper sull&#39;mRNA",src:a(65188).A+"",width:"1158",height:"686"})}),"\n",(0,n.jsx)(e.p,{children:"Il grafico sopra mostra la distribuzione delle probabilit\xe0 di misura delle bitstring campionate, con le energie corrispondenti per un'istanza di 42 nucleotidi e 80 qubit. Qui, le bitstring simboleggiano le coppie di nucleotidi. Illustra che la bitstring a energia pi\xf9 bassa trovata dal computer quantistico corrisponde a quella del risolutore classico comparativo, il che \xe8 ottimo. \xc8 mostrata anche la struttura ripiegata ottimale di quella catena di nucleotidi basata sulla bitstring a energia pi\xf9 bassa trovata dal computer quantistico."}),"\n",(0,n.jsx)(e.h2,{id:"conclusion",children:"Conclusione"}),"\n",(0,n.jsx)(e.p,{children:"Si spera che questi tre casi d'uso ti abbiano fornito abbastanza contesto per capire com'\xe8 il lavoro all'avanguardia nel campo in questo momento, e la fiducia per tentare nuovi esperimenti quantistici che potresti non aver fatto prima."}),"\n",(0,n.jsx)(e.p,{children:"Ricorda: il calcolo quantistico non \xe8 adatto a ogni problema. E questo \xe8 davvero solo una testimonianza di quanto siamo diventati bravi nell'informatica classica. Solo perch\xe9 pensi di poter applicare il calcolo quantistico a un problema non significa che produrr\xe0 risultati interessanti; devi considerare la scalabilit\xe0."}),"\n",(0,n.jsx)(e.p,{children:"La profondit\xe0 del circuito \xe8 un'arma a doppio taglio. Abbiamo bisogno che sia considerevolmente grande per fare lavoro interessante che i computer classici non possono fare, ma in questo momento non possiamo aumentare troppo la profondit\xe0 perch\xe9 il rumore hardware causer\xe0 la diminuzione della fedelt\xe0. Si tratta di trovare quel punto di equilibrio e sapere che \xe8 un obiettivo mobile. Quindi, prenditi un po' di tempo tra ora e la prossima lezione per pensare a un problema che hai incontrato nella tua ricerca, e come potresti affrontarlo con quello che abbiamo imparato finora. E hey, la tua soluzione potrebbe non funzionare, e va bene. Per questo si chiama ricerca."})]})}function d(i={}){const{wrapper:e}={...(0,t.R)(),...i.components};return e?(0,n.jsx)(e,{...i,children:(0,n.jsx)(u,{...i})}):u(i)}},52600(i,e,a){a.d(e,{A:()=>o});const o=a.p+"assets/images/complexity_classes-52979b588e98706373f7abc9b3f5f57c.avif"},77894(i,e,a){a.d(e,{A:()=>o});const o=a.p+"assets/images/hadron_paper-bc9c0a13fc3cd0e44b5c193902ce6dba.avif"},65188(i,e,a){a.d(e,{A:()=>o});const o=a.p+"assets/images/mrna_paper-4b1d694275f2539f69c49bfbb9b5ddd8.avif"},41923(i,e,a){a.d(e,{A:()=>o});const o=a.p+"assets/images/mrna_structure-962f2d5dfb98ac0a2e9c680e23d97ada.avif"},43410(i,e,a){a.d(e,{A:()=>o});const o=a.p+"assets/images/paper_results-aace6d8c4b97868e6cba7fc772e13ad9.avif"},28453(i,e,a){a.d(e,{R:()=>r,x:()=>s});var o=a(96540);const n={},t=o.createContext(n);function r(i){const e=o.useContext(t);return o.useMemo(function(){return"function"==typeof i?i(e):{...e,...i}},[e,i])}function s(i){let e;return e=i.disableParentContext?"function"==typeof i.components?i.components(n):i.components||n:r(i.components),o.createElement(t.Provider,{value:e},i.children)}}}]);